/**
 * RecordingControl — кнопка локальной записи урока.
 *
 * Workflow:
 *  1. Нажал «🔴 Запись» → запрашиваем displayMedia (экран+видео+звук) или
 *     просто audio+video с локального участника LiveKit
 *  2. Backend POST /recordings → presigned PUT URL в S3 + recordingId
 *  3. MediaRecorder пишет blobs локально, по 5-секундным чанкам
 *  4. На stop — собираем blob, PUT в S3 одним запросом
 *  5. PATCH /recordings/:id/finalize → обновляем metadata
 *
 * Если что-то падает посередине — PATCH /:id/fail.
 *
 * Доступно только учителю (controlled by parent — не рендерится у учеников).
 */

import { useEffect, useRef, useState } from 'react'
import { useLocalParticipant } from '@livekit/components-react'
import { createRecording, finalizeRecording, failRecording } from '../api/recordings'

interface Props {
  roomId: string
  slotId?: string
  studentId?: string
}

type State = 'idle' | 'starting' | 'recording' | 'uploading' | 'done' | 'error'

export default function RecordingControl({ roomId, slotId, studentId }: Props) {
  const { localParticipant } = useLocalParticipant()
  const [state, setState] = useState<State>('idle')
  const [errorMsg, setErrorMsg] = useState('')
  const [startedAt, setStartedAt] = useState<number | null>(null)
  const [duration, setDuration] = useState(0)

  const recorderRef = useRef<MediaRecorder | null>(null)
  const chunksRef = useRef<Blob[]>([])
  const recordingIdRef = useRef<string>('')
  const uploadUrlRef = useRef<string>('')
  const streamRef = useRef<MediaStream | null>(null)

  // Live duration counter
  useEffect(() => {
    if (!startedAt) { setDuration(0); return }
    const interval = setInterval(() => {
      setDuration(Math.floor((Date.now() - startedAt) / 1000))
    }, 1000)
    return () => clearInterval(interval)
  }, [startedAt])

  function fmtDuration(s: number) {
    const m = Math.floor(s / 60)
    const sec = s % 60
    return `${String(m).padStart(2, '0')}:${String(sec).padStart(2, '0')}`
  }

  async function startRecording() {
    if (state !== 'idle' && state !== 'done' && state !== 'error') return
    setState('starting')
    setErrorMsg('')
    try {
      // 1) Просим экран + системный звук + микрофон.
      // Если учитель отказал в screen — fallback на webcam.
      let stream: MediaStream
      try {
        const display = await navigator.mediaDevices.getDisplayMedia({
          video: { frameRate: 15 },
          audio: true,
        })
        // Микрофон отдельно — getDisplayMedia не всегда даёт mic
        try {
          const mic = await navigator.mediaDevices.getUserMedia({ audio: true })
          mic.getAudioTracks().forEach((t) => display.addTrack(t))
        } catch { /* ok без мика */ }
        stream = display
      } catch {
        // Fallback: пишем камеру+мик локально
        stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true })
      }
      streamRef.current = stream

      // 2) Backend — забронировать запись и получить presigned URL
      const mimeType = MediaRecorder.isTypeSupported('video/webm;codecs=vp9,opus')
        ? 'video/webm;codecs=vp9,opus'
        : 'video/webm'
      const reservation = await createRecording({ slotId, studentId, mimeType: 'video/webm' })
      recordingIdRef.current = reservation.recordingId
      uploadUrlRef.current = reservation.uploadUrl

      // 3) MediaRecorder
      const recorder = new MediaRecorder(stream, { mimeType, videoBitsPerSecond: 1_500_000 })
      chunksRef.current = []
      recorder.ondataavailable = (e) => { if (e.data.size > 0) chunksRef.current.push(e.data) }
      recorder.onstop = () => { void uploadAndFinalize() }
      recorder.onerror = (e) => { setErrorMsg(String(e)); setState('error') }

      recorder.start(5000) // 5-секундные чанки в памяти
      recorderRef.current = recorder
      setStartedAt(Date.now())
      setState('recording')

      // Если учитель закрыл share — стопимся
      stream.getVideoTracks()[0]?.addEventListener('ended', () => {
        if (recorder.state === 'recording') recorder.stop()
      })
    } catch (e) {
      console.error('[recording] start failed', e)
      setErrorMsg(e instanceof Error ? e.message : 'Не удалось начать запись')
      setState('error')
    }
  }

  function stopRecording() {
    const r = recorderRef.current
    if (!r || r.state !== 'recording') return
    setState('uploading')
    r.stop()
    streamRef.current?.getTracks().forEach((t) => t.stop())
  }

  async function uploadAndFinalize() {
    const id = recordingIdRef.current
    const url = uploadUrlRef.current
    if (!id || !url) { setState('error'); setErrorMsg('Нет recordingId'); return }
    try {
      const blob = new Blob(chunksRef.current, { type: 'video/webm' })
      const sizeBytes = blob.size
      const durationSec = startedAt ? Math.floor((Date.now() - startedAt) / 1000) : 0

      // PUT прямо в S3 через presigned URL
      const putRes = await fetch(url, {
        method: 'PUT',
        body: blob,
        headers: { 'Content-Type': 'video/webm' },
      })
      if (!putRes.ok) throw new Error(`S3 upload failed: ${putRes.status}`)

      await finalizeRecording(id, { sizeBytes, durationSec })
      setState('done')
      setStartedAt(null)
    } catch (e) {
      console.error('[recording] upload failed', e)
      setErrorMsg(e instanceof Error ? e.message : 'Загрузка не удалась')
      setState('error')
      try { await failRecording(id, errorMsg || 'upload failed') } catch { /* ignore */ }
    }
  }

  // Кнопка не доступна гостям без участника
  if (!localParticipant) return null

  if (state === 'recording') {
    return (
      <button
        onClick={stopRecording}
        className="ek-ctrl-btn"
        title="Остановить запись"
        style={{ background: '#dc2626', color: '#fff', borderColor: '#dc2626' }}
      >
        <span aria-hidden style={{ animation: 'rec-pulse 1.4s ease-in-out infinite' }}>⏹</span>{' '}
        <span className="ek-ctrl-label">{fmtDuration(duration)}</span>
        <style>{`
          @keyframes rec-pulse { 0%, 100% { opacity: 1 } 50% { opacity: .35 } }
        `}</style>
      </button>
    )
  }

  if (state === 'starting' || state === 'uploading') {
    return (
      <button disabled className="ek-ctrl-btn" style={{ opacity: 0.7 }}>
        ⏳ <span className="ek-ctrl-label">{state === 'starting' ? 'Старт…' : 'Загрузка…'}</span>
      </button>
    )
  }

  if (state === 'error') {
    return (
      <button onClick={startRecording} className="ek-ctrl-btn" title={errorMsg} style={{ background: '#fde2e2', color: '#dc2626', borderColor: '#dc2626' }}>
        ⚠ <span className="ek-ctrl-label">Ошибка — повторить</span>
      </button>
    )
  }

  return (
    <button onClick={startRecording} className="ek-ctrl-btn" title="Запись урока на ваш ПК → S3">
      <span aria-hidden style={{ color: '#dc2626' }}>🔴</span> <span className="ek-ctrl-label">{state === 'done' ? 'Запись готова' : 'Запись'}</span>
    </button>
  )
}
