import { api } from './client'

export type RecordingStatus = 'pending' | 'uploaded' | 'failed' | 'deleted'

export interface RecordingDto {
  id: string
  ownerId: string
  studentId: string | null
  slotId: string | null
  lessonReportId: string | null
  s3Bucket: string
  s3Key: string
  mimeType: string
  sizeBytes: number | null
  durationSec: number | null
  startedAt: string
  finalizedAt: string | null
  status: RecordingStatus
  createdAt: string
  updatedAt: string
}

export interface CreateRecordingResponse {
  recordingId: string
  uploadUrl: string
  s3Key: string
  s3Bucket: string
  expiresAt: string
}

export interface CreateRecordingPayload {
  slotId?: string | undefined
  studentId?: string | undefined
  lessonReportId?: string | undefined
  /** e.g. 'video/webm' or 'video/mp4'. Defaults to 'video/webm' on backend. */
  mimeType?: string | undefined
}

export interface FinalizeRecordingPayload {
  sizeBytes?: number | undefined
  durationSec?: number | undefined
}

export interface RecordingWithUrl {
  recording: RecordingDto
  downloadUrl: string
}

/** Step 1: ask backend for a presigned PUT URL + DB row. */
export function createRecording(
  payload: CreateRecordingPayload = {},
): Promise<CreateRecordingResponse> {
  return api.post<CreateRecordingResponse>('/recordings', payload)
}

/**
 * Step 2: upload the Blob from MediaRecorder directly to S3 via the presigned URL.
 *
 * Single PUT — multipart not needed for typical lesson recordings.
 * The Content-Type MUST match the mimeType passed to createRecording (it is part
 * of the SigV4 signature).
 */
export async function uploadRecordingBlob(
  uploadUrl: string,
  blob: Blob,
  mimeType?: string,
): Promise<void> {
  const res = await fetch(uploadUrl, {
    method: 'PUT',
    headers: {
      'Content-Type': mimeType ?? blob.type ?? 'video/webm',
    },
    body: blob,
  })
  if (!res.ok) {
    const text = await res.text().catch(() => res.statusText)
    throw Object.assign(new Error(`Recording upload failed: ${res.status} ${text}`), {
      status: res.status,
    })
  }
}

/** Step 3: tell backend the upload is complete (status='uploaded'). */
export function finalizeRecording(
  id: string,
  payload: FinalizeRecordingPayload = {},
): Promise<RecordingDto> {
  return api.patch<RecordingDto>(`/recordings/${id}/finalize`, payload)
}

/** Mark recording failed (e.g. upload error / cancelled). */
export function failRecording(id: string, reason?: string): Promise<void> {
  return api.patch<void>(`/recordings/${id}/fail`, { reason })
}

export function fetchMyRecordings(): Promise<RecordingDto[]> {
  return api.get<RecordingDto[]>('/recordings/my').catch(() => [])
}

export function fetchStudentRecordings(studentId: string): Promise<RecordingDto[]> {
  return api.get<RecordingDto[]>(`/recordings/student/${studentId}`).catch(() => [])
}

export function getRecording(id: string): Promise<RecordingWithUrl> {
  return api.get<RecordingWithUrl>(`/recordings/${id}`)
}

export function deleteRecording(id: string): Promise<void> {
  return api.delete<void>(`/recordings/${id}`)
}

/**
 * Convenience helper: create + upload + finalize in one call.
 *
 * @example
 *   const blob = new Blob(chunks, { type: 'video/webm' })
 *   const rec = await uploadLessonRecording(blob, { slotId, studentId, durationSec: 1820 })
 */
export async function uploadLessonRecording(
  blob: Blob,
  opts: CreateRecordingPayload & { durationSec?: number } = {},
): Promise<RecordingDto> {
  const mimeType = opts.mimeType ?? blob.type ?? 'video/webm'
  const created = await createRecording({ ...opts, mimeType })
  try {
    await uploadRecordingBlob(created.uploadUrl, blob, mimeType)
  } catch (err) {
    await failRecording(created.recordingId, (err as Error).message).catch(() => {})
    throw err
  }
  return finalizeRecording(created.recordingId, {
    sizeBytes: blob.size,
    durationSec: opts.durationSec,
  })
}
